+#[derive(Debug, Clone, Copy)]
+struct LogAssertions {
+    passed: u64,
+    failed: u64,
+}
+
+impl LogAssertions {
+    const fn new(passed: u64, failed: u64) -> Self {
+        Self { passed, failed }
+    }
+
+    const fn none() -> Self {
+        Self {
+            passed: 0,
+            failed: 0,
+        }
+    }
+
+    fn from_match(matches: bool) -> Self {
+        Self {
+            passed: u64::from(matches),
+            failed: u64::from(!matches),
+        }
+    }
+}
